import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.converter.xml.MappingJackson2XmlHttpMessageConverter;
import com.fasterxml.jackson.dataformat.xml.XmlMapper;
import com.fasterxml.jackson.dataformat.xml.ser.ToXmlGenerator;

import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.stream.XMLInputFactory;
import org.xml.sax.SAXException;
import javax.xml.parsers.ParserConfigurationException;

@Configuration
public class XmlSecurityConfig {

    /**
     * Secure XML parser configuration for Spring Boot REST controllers
     * Prevents XXE attacks by disabling external entity processing
     */
    @Bean
    public MappingJackson2XmlHttpMessageConverter mappingJackson2XmlHttpMessageConverter() {
        // Create secure XmlMapper with XXE protections
        XmlMapper xmlMapper = new XmlMapper();
        xmlMapper.configure(ToXmlGenerator.Feature.WRITE_XML_DECLARATION, true);

        return new MappingJackson2XmlHttpMessageConverter(xmlMapper);
    }

    /**
     * Secure DocumentBuilderFactory configuration
     * Use this when parsing XML with DOM
     */
    public static DocumentBuilderFactory createSecureDocumentBuilderFactory() 
            throws ParserConfigurationException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // Disable DTD processing entirely
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entities and DTDs
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // Disable XInclude processing
        factory.setXIncludeAware(false);

        // Disable entity expansion
        factory.setExpandEntityReferences(false);

        return factory;
    }

    /**
     * Secure SAXParserFactory configuration
     * Use this when parsing XML with SAX
     */
    public static SAXParserFactory createSecureSAXParserFactory() 
            throws SAXException, ParserConfigurationException {
        SAXParserFactory factory = SAXParserFactory.newInstance();

        // Disable DTD processing
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        return factory;
    }

    /**
     * Secure XMLInputFactory configuration (StAX)
     * Use this when parsing XML with StAX
     */
    public static XMLInputFactory createSecureXMLInputFactory() {
        XMLInputFactory factory = XMLInputFactory.newInstance();

        // Disable external entities
        factory.setProperty(XMLInputFactory.IS_SUPPORTING_EXTERNAL_ENTITIES, false);
        factory.setProperty(XMLInputFactory.SUPPORT_DTD, false);

        return factory;
    }
}

