import org.springframework.web.bind.annotation.*;
import org.w3c.dom.Document;
import javax.xml.parsers.DocumentBuilder;
import java.io.ByteArrayInputStream;

@RestController
@RequestMapping("/api/v1/data")
public class SecureXmlController {

    @PostMapping(consumes = "application/xml")
    public ResponseEntity<String> processXml(@RequestBody String xmlInput) {
        try {
            // Use secure DocumentBuilderFactory
            DocumentBuilderFactory factory = XmlSecurityConfig.createSecureDocumentBuilderFactory();
            DocumentBuilder builder = factory.newDocumentBuilder();

            // Parse XML safely
            Document doc = builder.parse(
                new ByteArrayInputStream(xmlInput.getBytes("UTF-8"))
            );

            // Process document...
            return ResponseEntity.ok("XML processed successfully");

        } catch (Exception e) {
            return ResponseEntity.badRequest().body("Invalid XML: " + e.getMessage());
        }
    }
}

using Microsoft.AspNetCore.Mvc;
using System.Xml;
using System.Xml.Linq;
using System.IO;

namespace SecureApi.Controllers
{
    /// <summary>
    /// Secure XML processing configuration for ASP.NET Core
    /// Prevents XXE attacks by disabling external entity resolution
    /// </summary>
    [ApiController]
    [Route("api/v1/[controller]")]
    public class SecureXmlController : ControllerBase
    {
        /// <summary>
        /// Secure XmlReaderSettings factory method
        /// Use this configuration for all XML parsing operations
        /// </summary>
        private static XmlReaderSettings GetSecureXmlReaderSettings()
        {
            return new XmlReaderSettings
            {
                // Prohibit DTD processing entirely (most secure)
                DtdProcessing = DtdProcessing.Prohibit,

                // Disable external entity resolution
                XmlResolver = null,

                // Limit document size to prevent billion laughs attack
                MaxCharactersFromEntities = 1024,
                MaxCharactersInDocument = 10485760, // 10 MB

                // Additional security settings
                IgnoreProcessingInstructions = true,
                IgnoreComments = true,

                // Enable validation for schema-based security
                ValidationType = ValidationType.Schema,
                ValidationFlags = System.Xml.Schema.XmlSchemaValidationFlags.ReportValidationWarnings
            };
        }

        /// <summary>
        /// Example: Secure XML processing with XmlReader
        /// </summary>
        [HttpPost("process")]
        [Consumes("application/xml")]
        public IActionResult ProcessXml([FromBody] string xmlContent)
        {
            try
            {
                using (var stringReader = new StringReader(xmlContent))
                using (var xmlReader = XmlReader.Create(stringReader, GetSecureXmlReaderSettings()))
                {
                    while (xmlReader.Read())
                    {
                        // Safely process XML elements
                        if (xmlReader.NodeType == XmlNodeType.Element)
                        {
                            Console.WriteLine($"Element: {xmlReader.Name}");
                        }
                    }
                }

                return Ok(new { message = "XML processed securely" });
            }
            catch (XmlException ex)
            {
                return BadRequest(new { error = "Invalid XML", details = ex.Message });
            }
        }

        /// <summary>
        /// Secure XDocument loading (LINQ to XML)
        /// </summary>
        [HttpPost("process-linq")]
        public IActionResult ProcessXmlLinq([FromBody] string xmlContent)
        {
            try
            {
                // XDocument.Load with secure settings
                using (var stringReader = new StringReader(xmlContent))
                using (var xmlReader = XmlReader.Create(stringReader, GetSecureXmlReaderSettings()))
                {
                    XDocument doc = XDocument.Load(xmlReader);

                    // Process document safely
                    var rootElement = doc.Root?.Name.LocalName;

                    return Ok(new { root = rootElement });
                }
            }
            catch (Exception ex)
            {
                return BadRequest(new { error = ex.Message });
            }
        }

        /// <summary>
        /// Legacy XmlDocument processing (secure configuration)
        /// Note: Prefer XmlReader or XDocument for new code
        /// </summary>
        [HttpPost("legacy")]
        public IActionResult ProcessLegacyXml([FromBody] string xmlContent)
        {
            var xmlDoc = new XmlDocument
            {
                // Critical: Set XmlResolver to null to prevent external entity resolution
                XmlResolver = null
            };

            try
            {
                // Load XML with secure XmlReader
                using (var stringReader = new StringReader(xmlContent))
                using (var xmlReader = XmlReader.Create(stringReader, GetSecureXmlReaderSettings()))
                {
                    xmlDoc.Load(xmlReader);
                }

                return Ok(new { nodes = xmlDoc.DocumentElement?.ChildNodes.Count });
            }
            catch (XmlException ex)
            {
                return BadRequest(new { error = ex.Message });
            }
        }
    }

    /// <summary>
    /// Global XML security configuration (Startup.cs / Program.cs)
    /// </summary>
    public class XmlSecurityConfiguration
    {
        public static void ConfigureXmlSecurity(IServiceCollection services)
        {
            // Configure JSON as default instead of XML when possible
            services.AddControllers(options =>
            {
                options.RespectBrowserAcceptHeader = true;
                options.ReturnHttpNotAcceptable = true;
            })
            .AddXmlSerializerFormatters(options =>
            {
                // Secure XmlSerializer configuration
                options.XmlReaderSettings = new XmlReaderSettings
                {
                    DtdProcessing = DtdProcessing.Prohibit,
                    XmlResolver = null
                };
            });
        }
    }
}

import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.ContentNegotiationConfigurer;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;
import org.springframework.boot.web.servlet.FilterRegistrationBean;
import org.springframework.context.annotation.Bean;
import org.springframework.http.MediaType;

import javax.servlet.*;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.regex.Pattern;
import javax.xml.XMLConstants;
import javax.xml.validation.Schema;
import javax.xml.validation.SchemaFactory;
import javax.xml.validation.Validator;
import javax.xml.transform.stream.StreamSource;
import java.io.StringReader;

@Configuration
public class XmlInputValidationConfig implements WebMvcConfigurer {

    /**
     * Restrict Content-Type negotiation - prefer JSON over XML
     */
    @Override
    public void configureContentNegotiation(ContentNegotiationConfigurer configurer) {
        configurer
            .favorParameter(false)
            .ignoreAcceptHeader(false)
            .defaultContentType(MediaType.APPLICATION_JSON)
            .mediaType("json", MediaType.APPLICATION_JSON)
            .mediaType("xml", MediaType.APPLICATION_XML);
    }

    /**
     * XML Security Filter - validates all XML requests
     */
    @Bean
    public FilterRegistrationBean<XmlSecurityFilter> xmlSecurityFilter() {
        FilterRegistrationBean<XmlSecurityFilter> registrationBean = new FilterRegistrationBean<>();
        registrationBean.setFilter(new XmlSecurityFilter());
        registrationBean.addUrlPatterns("/api/*");
        registrationBean.setOrder(1);
        return registrationBean;
    }

    /**
     * Custom filter to detect and block XXE payloads
     */
    public static class XmlSecurityFilter implements Filter {

        // Patterns indicating XXE attack attempts
        private static final Pattern XXE_DOCTYPE_PATTERN = 
            Pattern.compile("<!DOCTYPE\\s+[^>]*>", Pattern.CASE_INSENSITIVE);

        private static final Pattern XXE_ENTITY_PATTERN = 
            Pattern.compile("<!ENTITY\\s+[^>]*>", Pattern.CASE_INSENSITIVE);

        private static final Pattern XXE_SYSTEM_PATTERN = 
            Pattern.compile("SYSTEM\\s+[\"'][^\"']*[\"']", Pattern.CASE_INSENSITIVE);

        private static final Pattern XXE_PUBLIC_PATTERN = 
            Pattern.compile("PUBLIC\\s+[\"'][^\"']*[\"']", Pattern.CASE_INSENSITIVE);

        @Override
        public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
                throws IOException, ServletException {

            HttpServletRequest httpRequest = (HttpServletRequest) request;
            HttpServletResponse httpResponse = (HttpServletResponse) response;

            String contentType = httpRequest.getContentType();

            // Only inspect XML requests
            if (contentType != null && contentType.contains("xml")) {

                // Read request body
                String requestBody = httpRequest.getReader().lines()
                    .reduce("", (accumulator, actual) -> accumulator + actual);

                // Check request size (prevent billion laughs / entity expansion attacks)
                if (requestBody.length() > 1_000_000) { // 1 MB limit
                    httpResponse.setStatus(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE);
                    httpResponse.getWriter().write("{\"error\": \"XML payload too large\"}");
                    return;
                }

                // Detect suspicious XXE patterns
                if (XXE_DOCTYPE_PATTERN.matcher(requestBody).find() ||
                    XXE_ENTITY_PATTERN.matcher(requestBody).find() ||
                    XXE_SYSTEM_PATTERN.matcher(requestBody).find() ||
                    XXE_PUBLIC_PATTERN.matcher(requestBody).find()) {

                    // Log the attack attempt
                    System.err.println("XXE attack detected from: " + httpRequest.getRemoteAddr());

                    httpResponse.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                    httpResponse.setContentType("application/json");
                    httpResponse.getWriter().write(
                        "{\"error\": \"Invalid XML structure - external entities not allowed\"}"
                    );
                    return;
                }
            }

            chain.doFilter(request, response);
        }
    }

    /**
     * XML Schema Validation - enforce strict structure
     */
    public static class XmlSchemaValidator {

        /**
         * Validate XML against XSD schema
         */
        public static boolean validateAgainstSchema(String xmlContent, String xsdPath) {
            try {
                SchemaFactory factory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

                // Load schema
                Schema schema = factory.newSchema(new StreamSource(xsdPath));
                Validator validator = schema.newValidator();

                // Validate XML
                validator.validate(new StreamSource(new StringReader(xmlContent)));

                return true;
            } catch (Exception e) {
                System.err.println("XML validation failed: " + e.getMessage());
                return false;
            }
        }
    }
}

